LUNCH_FOODS = [
    {"name": "鸡胸沙拉", "calories": 520, "protein": 77.8, "carbs": 12.5, "price": 30.4, "category": "沙拉轻食", "intro": "鸡胸沙拉是高蛋白低碳水的健身餐代表，大块即食鸡胸肉搭配新鲜蔬菜，满足增肌减脂需求。", "taste": "鸡胸肉嫩而不柴，混合沙拉蔬菜清脆爽口，樱桃番茄的酸甜点睛，整体清新低卡。", "steps": [{"step": 1, "detail": "即食鸡胸肉切厚片或撕成条状", "time": "2分钟", "temp": "-"}, {"step": 2, "detail": "混合沙拉蔬菜用冰水浸泡5分钟后沥干（更脆）", "time": "5分钟", "temp": "冰水"}, {"step": 3, "detail": "樱桃番茄对半切开", "time": "1分钟", "temp": "-"}, {"step": 4, "detail": "所有材料装盘，淋油醋汁或低脂沙拉酱即可", "time": "1分钟", "temp": "-"}], "ingredients": [{"name": "即食鸡胸肉", "price": 18.5, "quantity": "300g"}, {"name": "混合沙拉蔬菜", "price": 9.9, "quantity": "150g"}, {"name": "樱桃番茄", "price": 2.0, "quantity": "50g"}], "img": "lunch.png"},
    {"name": "黑椒牛肉意面", "calories": 650, "protein": 60.9, "carbs": 113.0, "price": 30.5, "category": "西式", "intro": "黑椒牛肉意面是经典西式午餐，牛肉富含血红素铁有助预防贫血，搭配意面提供持久能量。", "taste": "牛肉嫩滑多汁，黑椒酱汁辛辣浓郁裹满每根意面，青椒清脆增香。", "steps": [{"step": 1, "detail": "意面放入加盐的沸水中煮8-10分钟至弹牙", "time": "10分钟", "temp": "沸水"}, {"step": 2, "detail": "牛肉片加少许生抽和淀粉腌制5分钟", "time": "5分钟", "temp": "-"}, {"step": 3, "detail": "热锅倒油大火翻炒牛肉至变色盛出", "time": "2分钟", "temp": "大火"}, {"step": 4, "detail": "同锅炒青椒丝和黑椒酱，加入意面和牛肉翻炒均匀即可", "time": "3分钟", "temp": "中火"}], "ingredients": [{"name": "意面", "price": 3.8, "quantity": "150g"}, {"name": "牛肉片", "price": 24.0, "quantity": "200g"}, {"name": "青椒", "price": 1.5, "quantity": "1个"}, {"name": "黑椒酱", "price": 1.2, "quantity": "20g"}], "img": "lunch.png"},
    {"name": "香煎巴沙鱼+糙米饭", "calories": 540, "protein": 42.2, "carbs": 78.3, "price": 20.6, "category": "海鲜类", "intro": "香煎巴沙鱼搭配糙米饭是优质蛋白与复合碳水的完美组合，巴沙鱼无刺肉质细嫩，糙米饭低GI持久供能。", "taste": "鱼排外皮金黄微脆内里雪白嫩滑，糙米饭嚼劲十足带坚果香，西蓝花清甜解腻。", "steps": [{"step": 1, "detail": "糙米提前浸泡30分钟，加1.5倍水电饭煲煮熟", "time": "40分钟", "temp": "-"}, {"step": 2, "detail": "巴沙鱼柳用厨房纸吸干水分，两面撒盐和黑胡椒", "time": "2分钟", "temp": "-"}, {"step": 3, "detail": "平底锅中火倒油，鱼柳每面煎3-4分钟至金黄", "time": "7分钟", "temp": "中火"}, {"step": 4, "detail": "西蓝花焯水2分钟捞出，与鱼和饭一起装盘", "time": "2分钟", "temp": "沸水"}], "ingredients": [{"name": "巴沙鱼柳", "price": 14.9, "quantity": "250g"}, {"name": "糙米", "price": 3.2, "quantity": "100g"}, {"name": "西蓝花", "price": 2.5, "quantity": "80g"}], "img": "lunch.png"},
    {"name": "咖喱鸡肉饭", "calories": 680, "protein": 55.0, "carbs": 153.0, "price": 18.5, "category": "米饭类", "intro": "咖喱鸡肉饭是日式洋食的经典，咖喱的暖辛与鸡肉的鲜嫩相得益彰，一锅出的便捷午餐。", "taste": "咖喱酱汁浓稠辛香微甜，鸡肉嫩滑土豆绵密，米饭吸满咖喱汁风味十足。", "steps": [{"step": 1, "detail": "鸡腿肉切块加盐腌制，土豆胡萝卜去皮切滚刀块", "time": "8分钟", "temp": "-"}, {"step": 2, "detail": "热油中火炒鸡肉至表面变色盛出", "time": "3分钟", "temp": "中火"}, {"step": 3, "detail": "同锅炒土豆胡萝卜3分钟，加入600ml水和咖喱块", "time": "15分钟", "temp": "中火→小火"}, {"step": 4, "detail": "汤汁变稠后加回鸡肉煮5分钟，浇在米饭上即可", "time": "5分钟", "temp": "小火"}], "ingredients": [{"name": "鸡腿肉", "price": 12.0, "quantity": "200g"}, {"name": "土豆", "price": 1.8, "quantity": "1个"}, {"name": "胡萝卜", "price": 1.0, "quantity": "半根"}, {"name": "咖喱块", "price": 2.5, "quantity": "20g"}, {"name": "大米", "price": 1.2, "quantity": "150g"}], "img": "lunch.png"},
    {"name": "鲜虾时蔬炒面", "calories": 600, "protein": 37.3, "carbs": 112.8, "price": 24.2, "category": "面点", "intro": "鲜虾时蔬炒面是一盘搞定的快手午餐，虾仁高蛋白低脂，搭配多种蔬菜营养全面。", "taste": "虾仁鲜甜弹牙，面条裹满酱汁咸香入味，卷心菜清甜脆嫩。", "steps": [{"step": 1, "detail": "鸡蛋面煮至八分熟捞出过凉水沥干", "time": "5分钟", "temp": "沸水"}, {"step": 2, "detail": "鲜虾仁加料酒腌制，卷心菜切丝", "time": "3分钟", "temp": "-"}, {"step": 3, "detail": "热油大火炒虾仁至变红盛出", "time": "1分钟", "temp": "大火"}, {"step": 4, "detail": "同锅炒卷心菜至软，加面条、虾仁和生抽翻炒均匀", "time": "3分钟", "temp": "大火"}], "ingredients": [{"name": "鲜虾仁", "price": 19.9, "quantity": "100g"}, {"name": "鸡蛋面", "price": 2.5, "quantity": "150g"}, {"name": "卷心菜", "price": 1.5, "quantity": "100g"}, {"name": "生抽", "price": 0.3, "quantity": "5g"}], "img": "lunch.png"},
    {"name": "豆腐牛肉煲+杂粮饭", "calories": 620, "protein": 54.7, "carbs": 95.1, "price": 28.5, "category": "肉类", "intro": "豆腐牛肉煲是一道高蛋白暖身煲菜，嫩豆腐与牛肉末的经典搭配，低脂高营养。", "taste": "豆腐嫩滑如脂吸满肉汁，牛肉末香浓入味，香菇增添菌鲜，汤汁拌饭绝佳。", "steps": [{"step": 1, "detail": "杂粮米淘洗后电饭煲煮熟", "time": "35分钟", "temp": "-"}, {"step": 2, "detail": "牛肉末加生抽料酒腌制，嫩豆腐切2cm方块", "time": "5分钟", "temp": "-"}, {"step": 3, "detail": "砂锅热油炒香香菇和牛肉末，加300ml水烧开", "time": "5分钟", "temp": "中火"}, {"step": 4, "detail": "放入豆腐小火炖10分钟，勾薄芡撒葱花出锅", "time": "10分钟", "temp": "小火"}], "ingredients": [{"name": "嫩豆腐", "price": 3.5, "quantity": "300g"}, {"name": "牛肉末", "price": 18.0, "quantity": "150g"}, {"name": "香菇", "price": 3.0, "quantity": "3朵"}, {"name": "杂粮（糙米+小米）", "price": 4.0, "quantity": "120g"}], "img": "lunch.png"},
    {"name": "土豆泥肉酱拌面", "calories": 650, "protein": 45.1, "carbs": 145.0, "price": 18.0, "category": "面点", "intro": "土豆泥肉酱拌面是创意融合午餐，绵密土豆泥代替部分面条降低升糖负荷，肉酱浓郁满足感强。", "taste": "土豆泥如云朵般绵密包裹面条，肉酱酸甜浓郁，口感丰富饱腹感极强。", "steps": [{"step": 1, "detail": "土豆去皮切块蒸15分钟，压成泥加少许牛奶调匀", "time": "18分钟", "temp": "大火蒸"}, {"step": 2, "detail": "猪肉末加番茄酱炒成肉酱", "time": "8分钟", "temp": "中火"}, {"step": 3, "detail": "面条煮熟捞出", "time": "5分钟", "temp": "沸水"}, {"step": 4, "detail": "面条上铺土豆泥再浇肉酱，拌匀食用", "time": "1分钟", "temp": "-"}], "ingredients": [{"name": "猪肉末", "price": 12.0, "quantity": "150g"}, {"name": "土豆", "price": 2.5, "quantity": "200g"}, {"name": "面条", "price": 2.0, "quantity": "150g"}, {"name": "番茄酱", "price": 1.5, "quantity": "30g"}], "img": "lunch.png"},
    {"name": "照烧鸡腿饭", "calories": 580, "protein": 53.1, "carbs": 135.4, "price": 16.9, "category": "米饭类", "intro": "照烧鸡腿饭是日式定食的经典，甜咸照烧汁渗透鸡腿肉，搭配蔬菜营养均衡。", "taste": "鸡皮煎至焦脆鸡肉多汁鲜嫩，照烧汁的甜咸在口中交织，米饭吸满酱汁粒粒美味。", "steps": [{"step": 1, "detail": "鸡腿去骨，用刀背拍松肉质，牙签扎孔便于入味", "time": "5分钟", "temp": "-"}, {"step": 2, "detail": "照烧汁（生抽+味醂+糖）腌制鸡腿15分钟", "time": "15分钟", "temp": "-"}, {"step": 3, "detail": "平底锅中火鸡皮朝下煎5分钟至金黄，翻面煎3分钟", "time": "8分钟", "temp": "中火"}, {"step": 4, "detail": "倒入剩余照烧汁小火收汁，西蓝花焯水摆盘，盖在米饭上", "time": "5分钟", "temp": "小火"}], "ingredients": [{"name": "鸡腿", "price": 12.0, "quantity": "1个（约200g）"}, {"name": "照烧汁", "price": 1.8, "quantity": "30g"}, {"name": "西蓝花", "price": 1.5, "quantity": "50g"}, {"name": "胡萝卜", "price": 0.4, "quantity": "20g"}, {"name": "大米", "price": 1.2, "quantity": "150g"}], "img": "lunch.png"},
    {"name": "番茄炒蛋+米饭", "calories": 560, "protein": 31.4, "carbs": 130.7, "price": 9.3, "category": "米饭类", "intro": "番茄炒蛋是中国家庭最熟悉的下饭菜，酸甜开胃，经济实惠且营养丰富，被称为国民第一菜。", "taste": "鸡蛋蓬松嫩滑吸满番茄酸甜汁，番茄软烂出汁，简单纯粹的家的味道。", "steps": [{"step": 1, "detail": "鸡蛋打散加少许盐和水搅匀（加水使蛋更嫩）", "time": "2分钟", "temp": "-"}, {"step": 2, "detail": "番茄切小块，热油大火炒鸡蛋至凝固盛出", "time": "1分钟", "temp": "大火"}, {"step": 3, "detail": "同锅炒番茄至软烂出汁，加番茄酱增色", "time": "3分钟", "temp": "中火"}, {"step": 4, "detail": "倒回鸡蛋翻炒均匀，加盐和葱花出锅，配米饭", "time": "1分钟", "temp": "中火"}], "ingredients": [{"name": "鸡蛋", "price": 3.6, "quantity": "3个"}, {"name": "番茄", "price": 4.0, "quantity": "2个"}, {"name": "番茄酱", "price": 0.5, "quantity": "10g"}, {"name": "大米", "price": 1.2, "quantity": "150g"}], "img": "lunch.png"},
    {"name": "香菇滑鸡煲仔饭", "calories": 600, "protein": 56.6, "carbs": 150.6, "price": 16.9, "category": "米饭类", "intro": "香菇滑鸡煲仔饭是广式经典，用砂锅或电饭煲一锅出，鸡肉嫩滑锅底有焦香锅巴。", "taste": "鸡肉腌制后嫩滑多汁，香菇的菌香渗入米饭，锅巴焦脆咸香，层次丰富。", "steps": [{"step": 1, "detail": "鸡腿肉切块加生抽、蚝油、姜丝、淀粉腌制20分钟", "time": "20分钟", "temp": "-"}, {"step": 2, "detail": "干香菇泡发切片，大米淘洗后加水泡15分钟", "time": "15分钟", "temp": "-"}, {"step": 3, "detail": "砂锅（或电饭煲）煮米饭，水开后铺上鸡肉和香菇", "time": "15分钟", "temp": "中火"}, {"step": 4, "detail": "盖盖小火焖10分钟，沿锅边淋一圈油产生锅巴，关火焖3分钟", "time": "13分钟", "temp": "小火→余温"}], "ingredients": [{"name": "鸡腿肉", "price": 12.0, "quantity": "200g"}, {"name": "干香菇", "price": 3.0, "quantity": "4朵"}, {"name": "大米", "price": 1.5, "quantity": "180g"}, {"name": "生抽", "price": 0.3, "quantity": "5g"}, {"name": "姜丝", "price": 0.1, "quantity": "2g"}], "img": "lunch.png"},
    {"name": "蒜香排骨+白米饭", "calories": 780, "protein": 50.5, "carbs": 115.5, "price": 30.5, "category": "肉类", "intro": "蒜香排骨是让人满足的硬菜午餐，排骨富含胶原蛋白和钙质，蒜香浓郁勾起食欲。", "taste": "外皮焦脆蒜香扑鼻，排骨肉嫩脱骨，油脂的香气与蒜味完美融合。", "steps": [{"step": 1, "detail": "肋排斩小段，加蒜末、生抽、料酒腌制30分钟", "time": "30分钟", "temp": "-"}, {"step": 2, "detail": "烤箱预热200°C，排骨摆烤盘上", "time": "5分钟", "temp": "200°C预热"}, {"step": 3, "detail": "烤20分钟后翻面，刷一层蜂蜜蒜蓉酱", "time": "20分钟", "temp": "200°C"}, {"step": 4, "detail": "再烤10分钟至表面焦黄，配白米饭食用", "time": "10分钟", "temp": "200°C"}], "ingredients": [{"name": "肋排", "price": 28.0, "quantity": "250g"}, {"name": "蒜末", "price": 0.8, "quantity": "15g"}, {"name": "生抽", "price": 0.5, "quantity": "10g"}, {"name": "大米", "price": 1.2, "quantity": "150g"}], "img": "lunch.png"},
    {"name": "金枪鱼饭团+味噌汤", "calories": 490, "protein": 21.1, "carbs": 60.4, "price": 12.9, "category": "米饭类", "intro": "金枪鱼饭团配味噌汤是日式轻午餐，方便快捷营养均衡，水浸金枪鱼低脂高蛋白。", "taste": "饭团中海苔的鲜和金枪鱼的咸香交融，味噌汤醇厚温暖，豆腐嫩滑。", "steps": [{"step": 1, "detail": "水浸金枪鱼沥干，加少许沙拉酱拌匀", "time": "2分钟", "temp": "-"}, {"step": 2, "detail": "手心沾水取米饭压扁，放金枪鱼馅包成三角形", "time": "3分钟", "temp": "-"}, {"step": 3, "detail": "底部包海苔，表面撒芝麻", "time": "1分钟", "temp": "-"}, {"step": 4, "detail": "味噌酱加水煮开，加豆腐丁和海带煮3分钟即成味噌汤", "time": "5分钟", "temp": "中火"}], "ingredients": [{"name": "水浸金枪鱼罐头", "price": 9.0, "quantity": "半罐"}, {"name": "米饭", "price": 1.6, "quantity": "200g"}, {"name": "海苔", "price": 1.0, "quantity": "2片"}, {"name": "味噌酱", "price": 1.0, "quantity": "15g"}, {"name": "豆腐", "price": 0.3, "quantity": "30g"}], "img": "lunch.png"},
    {"name": "红烧牛肉面", "calories": 650, "protein": 48.0, "carbs": 130.0, "price": 22.0, "category": "面点", "intro": "红烧牛肉面是中式面食的经典之作，牛肉炖至酥烂入味，汤浓面筋道，一碗暖身解馋。", "taste": "牛肉酥烂醇香，汤底酱红浓郁带五香，面条筋道挂满汤汁，青菜清脆解腻。", "steps": [{"step": 1, "detail": "牛腩切块焯水去血沫，捞出冲洗干净", "time": "8分钟", "temp": "沸水"}, {"step": 2, "detail": "热油炒香姜葱八角桂皮，加牛肉块和豆瓣酱翻炒上色", "time": "5分钟", "temp": "中火"}, {"step": 3, "detail": "加料酒生抽老抽和足量热水，大火烧开转小火炖1.5小时", "time": "90分钟", "temp": "小火"}, {"step": 4, "detail": "另起锅煮面条，捞出盛碗，浇上牛肉汤和牛肉，焯青菜摆上", "time": "5分钟", "temp": "沸水"}], "ingredients": [{"name": "牛腩", "price": 15.0, "quantity": "200g"}, {"name": "面条", "price": 2.5, "quantity": "150g"}, {"name": "青菜", "price": 1.5, "quantity": "2棵"}, {"name": "香料包(八角桂皮等)", "price": 3.0, "quantity": "1份"}], "img": "lunch.png"},
    {"name": "宫保鸡丁+米饭", "calories": 580, "protein": 45.0, "carbs": 125.0, "price": 15.0, "category": "米饭类", "intro": "宫保鸡丁是川菜经典，鸡丁嫩滑花生酥脆，酸甜微辣的口感令人食欲大开。", "taste": "鸡丁嫩滑多汁，花生酥脆咸香，酱汁酸甜微辣，层次分明下饭神器。", "steps": [{"step": 1, "detail": "鸡胸肉切1.5cm丁，加料酒、淀粉、少许盐腌制15分钟", "time": "18分钟", "temp": "-"}, {"step": 2, "detail": "调碗汁：生抽、醋、糖、淀粉、水混合备用", "time": "2分钟", "temp": "-"}, {"step": 3, "detail": "热油中火炒鸡丁至变白盛出，同锅炒香干辣椒和花椒", "time": "3分钟", "temp": "中火"}, {"step": 4, "detail": "倒入鸡丁和碗汁大火翻炒收汁，加花生米和葱段翻匀出锅配米饭", "time": "2分钟", "temp": "大火"}], "ingredients": [{"name": "鸡胸肉", "price": 10.0, "quantity": "200g"}, {"name": "花生米", "price": 2.0, "quantity": "30g"}, {"name": "干辣椒", "price": 0.5, "quantity": "5个"}, {"name": "葱段", "price": 0.3, "quantity": "10g"}, {"name": "大米", "price": 1.2, "quantity": "150g"}], "img": "lunch.png"},
    {"name": "麻辣香锅（单人份）", "calories": 700, "protein": 52.0, "carbs": 80.0, "price": 28.0, "category": "肉类", "intro": "麻辣香锅是近年来风靡的川味干锅，自选食材一锅炒制，麻辣鲜香，适合重口味爱好者。", "taste": "麻辣味强劲刺激舌尖，各种食材吸满红油酱香，藕片脆土豆糯虾仁弹。", "steps": [{"step": 1, "detail": "所有食材预处理：虾开背去线，藕切片，土豆切片泡水，木耳泡发", "time": "15分钟", "temp": "-"}, {"step": 2, "detail": "分别焯水：藕片土豆片2分钟，虾仁1分钟，捞出沥干", "time": "5分钟", "temp": "沸水"}, {"step": 3, "detail": "热油小火炒香火锅底料和干辣椒花椒至出红油", "time": "3分钟", "temp": "小火"}, {"step": 4, "detail": "加入所有食材大火翻炒3分钟，加生抽和糖调味，撒芝麻出锅", "time": "5分钟", "temp": "大火"}], "ingredients": [{"name": "虾仁", "price": 10.0, "quantity": "100g"}, {"name": "鸡翅中", "price": 8.0, "quantity": "4个"}, {"name": "藕片", "price": 2.0, "quantity": "100g"}, {"name": "土豆", "price": 1.5, "quantity": "1个"}, {"name": "火锅底料", "price": 4.5, "quantity": "50g"}, {"name": "木耳", "price": 2.0, "quantity": "30g"}], "img": "lunch.png"},
    {"name": "日式亲子丼", "calories": 550, "protein": 42.0, "carbs": 130.0, "price": 12.0, "category": "米饭类", "intro": "亲子丼是日式盖饭的温暖代表，鸡肉和鸡蛋的亲子组合，半熟蛋液包裹米饭温柔治愈。", "taste": "蛋液柔滑半凝固包裹米饭，鸡肉鲜美多汁，酱汁甜咸适口，洋葱清甜。", "steps": [{"step": 1, "detail": "鸡腿肉去骨切块，洋葱切丝，调配酱汁（生抽+味醂+糖+水）", "time": "5分钟", "temp": "-"}, {"step": 2, "detail": "小锅倒入酱汁和洋葱丝，中火煮至洋葱透明", "time": "3分钟", "temp": "中火"}, {"step": 3, "detail": "放入鸡肉块煮至熟透约5分钟", "time": "5分钟", "temp": "中火"}, {"step": 4, "detail": "鸡蛋稍打散（保留蛋白蛋黄分离感），均匀淋入，半凝固时关火盖在米饭上", "time": "1分钟", "temp": "中火"}], "ingredients": [{"name": "鸡腿肉", "price": 8.0, "quantity": "150g"}, {"name": "鸡蛋", "price": 2.4, "quantity": "2个"}, {"name": "洋葱", "price": 1.0, "quantity": "半个"}, {"name": "大米", "price": 1.2, "quantity": "150g"}], "img": "lunch.png"},
    {"name": "回锅肉+米饭", "calories": 680, "protein": 38.0, "carbs": 120.0, "price": 16.0, "category": "肉类", "intro": "回锅肉是川菜之首，煮后回锅炒制的五花肉肥而不腻，搭配蒜苗和豆瓣酱香气逼人。", "taste": "肉片卷曲焦香微脆，肥肉部分透明不腻，豆瓣酱的咸辣与蒜苗清香绝配。", "steps": [{"step": 1, "detail": "五花肉整块冷水入锅，加姜片料酒煮20分钟至筷子能扎透", "time": "22分钟", "temp": "中火"}, {"step": 2, "detail": "捞出晾凉切薄片（约2mm厚），蒜苗切斜段", "time": "5分钟", "temp": "-"}, {"step": 3, "detail": "热锅少油中火煸炒肉片至卷曲出油，拨到一边加豆瓣酱炒出红油", "time": "5分钟", "temp": "中火"}, {"step": 4, "detail": "加蒜苗段大火翻炒1分钟，加少许糖提鲜出锅配米饭", "time": "1分钟", "temp": "大火"}], "ingredients": [{"name": "五花肉", "price": 12.0, "quantity": "200g"}, {"name": "蒜苗", "price": 2.0, "quantity": "3根"}, {"name": "豆瓣酱", "price": 1.0, "quantity": "15g"}, {"name": "姜片", "price": 0.2, "quantity": "3片"}, {"name": "大米", "price": 1.2, "quantity": "150g"}], "img": "lunch.png"},
    {"name": "麻婆豆腐+米饭", "calories": 520, "protein": 32.0, "carbs": 125.0, "price": 8.0, "category": "米饭类", "intro": "麻婆豆腐是川菜经典中的经典，嫩豆腐与牛肉末的完美结合，麻辣烫香嫩鲜，成本低廉。", "taste": "豆腐嫩滑烫口，肉末酥香，麻辣味刺激味蕾，花椒的麻在唇齿间久久不散。", "steps": [{"step": 1, "detail": "嫩豆腐切2cm方块，入加了盐的沸水中焯2分钟捞出", "time": "3分钟", "temp": "沸水"}, {"step": 2, "detail": "热油中火炒牛肉末至酥香，加豆瓣酱炒出红油", "time": "5分钟", "temp": "中火"}, {"step": 3, "detail": "加200ml水烧开，轻轻放入豆腐块，小火煮5分钟入味", "time": "5分钟", "temp": "小火"}, {"step": 4, "detail": "分两次勾芡使汤汁浓稠包裹豆腐，撒花椒粉和葱花出锅", "time": "3分钟", "temp": "小火"}], "ingredients": [{"name": "嫩豆腐", "price": 3.0, "quantity": "400g"}, {"name": "牛肉末", "price": 3.5, "quantity": "50g"}, {"name": "豆瓣酱", "price": 0.5, "quantity": "10g"}, {"name": "花椒粉", "price": 0.2, "quantity": "2g"}, {"name": "大米", "price": 1.2, "quantity": "150g"}], "img": "lunch.png"},
    {"name": "鱼香肉丝+米饭", "calories": 550, "protein": 35.0, "carbs": 128.0, "price": 13.0, "category": "米饭类", "intro": "鱼香肉丝虽名鱼却无鱼，以泡椒葱姜蒜糖醋调出鱼香味型，是考验川菜功力的经典菜。", "taste": "肉丝嫩滑，木耳脆爽，酸甜微辣层次分明，鱼香味型独特迷人。", "steps": [{"step": 1, "detail": "猪里脊切丝加料酒、盐、淀粉腌制15分钟，木耳泡发切丝，胡萝卜青椒切丝", "time": "18分钟", "temp": "-"}, {"step": 2, "detail": "调鱼香汁：生抽、醋、糖、淀粉、水按1:1:1:0.5:2混合", "time": "2分钟", "temp": "-"}, {"step": 3, "detail": "热油大火滑炒肉丝至变白盛出", "time": "1分钟", "temp": "大火"}, {"step": 4, "detail": "同锅炒香泡椒末和葱姜蒜，加入蔬菜丝炒软，倒回肉丝和鱼香汁翻炒均匀", "time": "3分钟", "temp": "大火"}], "ingredients": [{"name": "猪里脊", "price": 8.0, "quantity": "150g"}, {"name": "木耳", "price": 1.5, "quantity": "20g"}, {"name": "胡萝卜", "price": 0.5, "quantity": "30g"}, {"name": "青椒", "price": 1.0, "quantity": "1个"}, {"name": "泡椒", "price": 0.8, "quantity": "10g"}, {"name": "大米", "price": 1.2, "quantity": "150g"}], "img": "lunch.png"},
    {"name": "酸菜鱼+米饭", "calories": 500, "protein": 48.0, "carbs": 115.0, "price": 25.0, "category": "海鲜类", "intro": "酸菜鱼是重庆江湖菜代表，鱼片嫩滑酸菜爽脆，汤底酸辣开胃，是午餐硬菜之选。", "taste": "鱼片雪白嫩滑入口即化，酸菜的酸爽与泡椒的辣交融，汤鲜味浓。", "steps": [{"step": 1, "detail": "草鱼片成薄片，加蛋清、淀粉、盐抓匀腌制15分钟", "time": "18分钟", "temp": "-"}, {"step": 2, "detail": "酸菜切段，热油炒香泡椒和酸菜，加800ml水煮10分钟出味", "time": "12分钟", "temp": "中火"}, {"step": 3, "detail": "汤烧至微沸，逐片放入鱼片，不要搅动", "time": "2分钟", "temp": "中火"}, {"step": 4, "detail": "鱼片变白即熟（约1分钟），连汤倒入大碗，撒葱花干辣椒，浇热油出香", "time": "2分钟", "temp": "大火"}], "ingredients": [{"name": "草鱼片", "price": 15.0, "quantity": "250g"}, {"name": "酸菜", "price": 4.0, "quantity": "150g"}, {"name": "泡椒", "price": 1.5, "quantity": "20g"}, {"name": "蛋清", "price": 0.5, "quantity": "1个"}, {"name": "大米", "price": 1.2, "quantity": "150g"}], "img": "lunch.png"}
]